{"version":3,"file":"index.cjs","sources":["../../src/preload/index.ts"],"sourcesContent":["/**\n * Preload 脚本\n * \n * 职责: 安全地暴露主进程 API 到渲染进程\n */\n\nconst { contextBridge, ipcRenderer } = require('electron')\n\n// IPC 频道白名单\nconst validChannels = [\n  // 窗口\n  'window:minimize',\n  'window:maximize',\n  'window:close',\n  'window:toggleFullscreen',\n  'window:getState',\n  \n  // 番剧\n  'anime:list',\n  'anime:detail',\n  'anime:episodes',\n  'anime:search',\n  'anime:bangumi',\n  'anime:video',\n  'anime:cache:status',\n  'anime:cache:refresh',\n  \n  // 收藏\n  'favorite:list',\n  'favorite:add',\n  'favorite:remove',\n  'favorite:check',\n  \n  // 播放历史\n  'history:list',\n  'history:save',\n  'history:progress',\n  'history:clear',\n  \n  // 设置\n  'settings:get',\n  'settings:set',\n  'settings:getAll',\n  \n  // 下载\n  'download:list',\n  'download:add',\n  'download:pause',\n  'download:resume',\n  'download:cancel',\n  \n  // 系统\n  'system:showItemInFolder',\n  'system:openExternal',\n  \n  // 更新\n  'update:check',\n  'update:download',\n  'update:install'\n]\n\n// API 定义\nexport interface ElectronAPI {\n  // 窗口控制\n  window: {\n    minimize: () => Promise<void>\n    maximize: () => Promise<void>\n    close: () => Promise<void>\n    toggleFullscreen: () => Promise<void>\n    getState: () => Promise<{ maximized: boolean; minimized: boolean; fullscreen: boolean; focused: boolean }>\n  }\n  \n  // 番剧\n  anime: {\n    getList: (params: { page: number; pageSize?: number }) => Promise<any>\n    getDetail: (params: { id: string }) => Promise<any>\n    getEpisodes: (params: { id: string }) => Promise<any>\n    search: (params: { keyword: string; page?: number }) => Promise<any>\n    getBangumiInfo: (params: { id: string }) => Promise<any>\n    extractVideo: (params: { episodeUrl: string }) => Promise<any>\n    getCacheStatus: () => Promise<any>\n    refreshCache: () => Promise<any>\n  }\n  \n  // 收藏\n  favorite: {\n    getList: () => Promise<any>\n    add: (params: { animeId: string; title: string; coverUrl?: string; detailUrl: string }) => Promise<any>\n    remove: (params: { animeId: string }) => Promise<any>\n    check: (params: { animeId: string }) => Promise<any>\n  }\n  \n  // 播放历史\n  history: {\n    getList: (params?: { limit?: number }) => Promise<any>\n    save: (params: {\n      animeId: string\n      animeTitle: string\n      episodeId: string\n      episodeNum: number\n      positionSeconds: number\n      totalSeconds: number\n      coverUrl?: string\n    }) => Promise<any>\n    getProgress: (params: { animeId: string; episodeId: string }) => Promise<any>\n    clear: () => Promise<any>\n  }\n  \n  // 设置\n  settings: {\n    get: (params: { key: string }) => Promise<any>\n    set: (params: { key: string; value: string }) => Promise<any>\n    getAll: () => Promise<any>\n  }\n  \n  // 下载\n  download: {\n    getList: () => Promise<any>\n    add: (params: { url: string; filename: string }) => Promise<any>\n    pause: (params: { taskId: string }) => Promise<any>\n    resume: (params: { taskId: string }) => Promise<any>\n    cancel: (params: { taskId: string }) => Promise<any>\n    onProgress: (callback: (task: any) => void) => void\n  }\n  \n  // 系统\n  system: {\n    showItemInFolder: (params: { path: string }) => Promise<void>\n    openExternal: (params: { url: string }) => Promise<void>\n  }\n  \n  // 更新\n  update: {\n    check: () => Promise<any>\n    download: () => Promise<any>\n    install: () => Promise<any>\n    onAvailable: (callback: (info: any) => void) => void\n    onProgress: (callback: (progress: number) => void) => void\n    onDownloaded: (callback: () => void) => void\n  }\n}\n\n// 安全的 IPC 调用\nconst invoke = async (channel: string, ...args: any[]): Promise<any> => {\n  if (validChannels.includes(channel)) {\n    return ipcRenderer.invoke(channel, ...args)\n  }\n  throw new Error(`Invalid channel: ${channel}`)\n}\n\n// 事件监听\nconst on = (channel: string, callback: (...args: any[]) => void): void => {\n  if (validChannels.includes(channel)) {\n    ipcRenderer.on(channel, (_, ...args) => callback(...args))\n  }\n}\n\n// 暴露 API\nconst api: ElectronAPI = {\n  window: {\n    minimize: () => invoke('window:minimize'),\n    maximize: () => invoke('window:maximize'),\n    close: () => invoke('window:close'),\n    toggleFullscreen: () => invoke('window:toggleFullscreen'),\n    getState: () => invoke('window:getState')\n  },\n  \n  anime: {\n    getList: (params) => invoke('anime:list', params),\n    getDetail: (params) => invoke('anime:detail', params),\n    getEpisodes: (params) => invoke('anime:episodes', params),\n    search: (params) => invoke('anime:search', params),\n    getBangumiInfo: (params) => invoke('anime:bangumi', params),\n    extractVideo: (params) => invoke('anime:video', params),\n    getCacheStatus: () => invoke('anime:cache:status'),\n    refreshCache: () => invoke('anime:cache:refresh')\n  },\n  \n  favorite: {\n    getList: () => invoke('favorite:list'),\n    add: (params) => invoke('favorite:add', params),\n    remove: (params) => invoke('favorite:remove', params),\n    check: (params) => invoke('favorite:check', params)\n  },\n  \n  history: {\n    getList: (params) => invoke('history:list', params),\n    save: (params) => invoke('history:save', params),\n    getProgress: (params) => invoke('history:progress', params),\n    clear: () => invoke('history:clear')\n  },\n  \n  settings: {\n    get: (params) => invoke('settings:get', params),\n    set: (params) => invoke('settings:set', params),\n    getAll: () => invoke('settings:getAll')\n  },\n  \n  download: {\n    getList: () => invoke('download:list'),\n    add: (params) => invoke('download:add', params),\n    pause: (params) => invoke('download:pause', params),\n    resume: (params) => invoke('download:resume', params),\n    cancel: (params) => invoke('download:cancel', params),\n    onProgress: (callback) => on('download:progress', callback)\n  },\n  \n  system: {\n    showItemInFolder: (params) => invoke('system:showItemInFolder', params),\n    openExternal: (params) => invoke('system:openExternal', params)\n  },\n  \n  update: {\n    check: () => invoke('update:check'),\n    download: () => invoke('update:download'),\n    install: () => invoke('update:install'),\n    onAvailable: (callback) => on('update:available', callback),\n    onProgress: (callback) => on('update:progress', callback),\n    onDownloaded: (callback) => on('update:downloaded', callback)\n  }\n}\n\n// 暴露到 window.api\nconsole.log('[Preload] Starting to expose API...')\ntry {\n  contextBridge.exposeInMainWorld('api', api)\n  console.log('[Preload] API exposed successfully')\n} catch (error) {\n  console.error('[Preload] Failed to expose API:', error)\n}\n\n// 类型声明\ndeclare global {\n  interface Window {\n    api: ElectronAPI\n  }\n}\n"],"names":[],"mappings":";AAMA,MAAM,EAAE,eAAe,gBAAgB,QAAQ,UAAU;AAGzD,MAAM,gBAAgB;AAAA;AAAA,EAEpB;AAAA,EACA;AAAA,EACA;AAAA,EACA;AAAA,EACA;AAAA;AAAA,EAGA;AAAA,EACA;AAAA,EACA;AAAA,EACA;AAAA,EACA;AAAA,EACA;AAAA,EACA;AAAA,EACA;AAAA;AAAA,EAGA;AAAA,EACA;AAAA,EACA;AAAA,EACA;AAAA;AAAA,EAGA;AAAA,EACA;AAAA,EACA;AAAA,EACA;AAAA;AAAA,EAGA;AAAA,EACA;AAAA,EACA;AAAA;AAAA,EAGA;AAAA,EACA;AAAA,EACA;AAAA,EACA;AAAA,EACA;AAAA;AAAA,EAGA;AAAA,EACA;AAAA;AAAA,EAGA;AAAA,EACA;AAAA,EACA;AACF;AAoFA,MAAM,SAAS,OAAO,YAAoB,SAA8B;AACtE,MAAI,cAAc,SAAS,OAAO,GAAG;AACnC,WAAO,YAAY,OAAO,SAAS,GAAG,IAAI;AAAA,EAC5C;AACA,QAAM,IAAI,MAAM,oBAAoB,OAAO,EAAE;AAC/C;AAGA,MAAM,KAAK,CAAC,SAAiB,aAA6C;AACxE,MAAI,cAAc,SAAS,OAAO,GAAG;AACnC,gBAAY,GAAG,SAAS,CAAC,MAAM,SAAS,SAAS,GAAG,IAAI,CAAC;AAAA,EAC3D;AACF;AAGA,MAAM,MAAmB;AAAA,EACvB,QAAQ;AAAA,IACN,UAAU,MAAM,OAAO,iBAAiB;AAAA,IACxC,UAAU,MAAM,OAAO,iBAAiB;AAAA,IACxC,OAAO,MAAM,OAAO,cAAc;AAAA,IAClC,kBAAkB,MAAM,OAAO,yBAAyB;AAAA,IACxD,UAAU,MAAM,OAAO,iBAAiB;AAAA,EAAA;AAAA,EAG1C,OAAO;AAAA,IACL,SAAS,CAAC,WAAW,OAAO,cAAc,MAAM;AAAA,IAChD,WAAW,CAAC,WAAW,OAAO,gBAAgB,MAAM;AAAA,IACpD,aAAa,CAAC,WAAW,OAAO,kBAAkB,MAAM;AAAA,IACxD,QAAQ,CAAC,WAAW,OAAO,gBAAgB,MAAM;AAAA,IACjD,gBAAgB,CAAC,WAAW,OAAO,iBAAiB,MAAM;AAAA,IAC1D,cAAc,CAAC,WAAW,OAAO,eAAe,MAAM;AAAA,IACtD,gBAAgB,MAAM,OAAO,oBAAoB;AAAA,IACjD,cAAc,MAAM,OAAO,qBAAqB;AAAA,EAAA;AAAA,EAGlD,UAAU;AAAA,IACR,SAAS,MAAM,OAAO,eAAe;AAAA,IACrC,KAAK,CAAC,WAAW,OAAO,gBAAgB,MAAM;AAAA,IAC9C,QAAQ,CAAC,WAAW,OAAO,mBAAmB,MAAM;AAAA,IACpD,OAAO,CAAC,WAAW,OAAO,kBAAkB,MAAM;AAAA,EAAA;AAAA,EAGpD,SAAS;AAAA,IACP,SAAS,CAAC,WAAW,OAAO,gBAAgB,MAAM;AAAA,IAClD,MAAM,CAAC,WAAW,OAAO,gBAAgB,MAAM;AAAA,IAC/C,aAAa,CAAC,WAAW,OAAO,oBAAoB,MAAM;AAAA,IAC1D,OAAO,MAAM,OAAO,eAAe;AAAA,EAAA;AAAA,EAGrC,UAAU;AAAA,IACR,KAAK,CAAC,WAAW,OAAO,gBAAgB,MAAM;AAAA,IAC9C,KAAK,CAAC,WAAW,OAAO,gBAAgB,MAAM;AAAA,IAC9C,QAAQ,MAAM,OAAO,iBAAiB;AAAA,EAAA;AAAA,EAGxC,UAAU;AAAA,IACR,SAAS,MAAM,OAAO,eAAe;AAAA,IACrC,KAAK,CAAC,WAAW,OAAO,gBAAgB,MAAM;AAAA,IAC9C,OAAO,CAAC,WAAW,OAAO,kBAAkB,MAAM;AAAA,IAClD,QAAQ,CAAC,WAAW,OAAO,mBAAmB,MAAM;AAAA,IACpD,QAAQ,CAAC,WAAW,OAAO,mBAAmB,MAAM;AAAA,IACpD,YAAY,CAAC,aAAa,GAAG,qBAAqB,QAAQ;AAAA,EAAA;AAAA,EAG5D,QAAQ;AAAA,IACN,kBAAkB,CAAC,WAAW,OAAO,2BAA2B,MAAM;AAAA,IACtE,cAAc,CAAC,WAAW,OAAO,uBAAuB,MAAM;AAAA,EAAA;AAAA,EAGhE,QAAQ;AAAA,IACN,OAAO,MAAM,OAAO,cAAc;AAAA,IAClC,UAAU,MAAM,OAAO,iBAAiB;AAAA,IACxC,SAAS,MAAM,OAAO,gBAAgB;AAAA,IACtC,aAAa,CAAC,aAAa,GAAG,oBAAoB,QAAQ;AAAA,IAC1D,YAAY,CAAC,aAAa,GAAG,mBAAmB,QAAQ;AAAA,IACxD,cAAc,CAAC,aAAa,GAAG,qBAAqB,QAAQ;AAAA,EAAA;AAEhE;AAGA,QAAQ,IAAI,qCAAqC;AACjD,IAAI;AACF,gBAAc,kBAAkB,OAAO,GAAG;AAC1C,UAAQ,IAAI,oCAAoC;AAClD,SAAS,OAAO;AACd,UAAQ,MAAM,mCAAmC,KAAK;AACxD;"}AO;AACd,cAAQ,MAAM,mCAAmC,KAAK;AAAA,IACxD;AAAA;AAAA;"}